plugin.detectCode:
const t = input.trim();
if (!t || t.includes('\n')) return 0;
const hasSpaces = t.includes(' ');
return hasSpaces ? 0.7 : 0.2;

plugin.executeCode:
const lines = input.split('\n').map(line => {
  return line.trim()
    .toLowerCase()
    // Replace accented characters
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    // Replace & with 'and'
    .replace(/&/g, 'and')
    // Remove characters that are not alphanumeric, spaces, or hyphens
    .replace(/[^a-z0-9\s-]/g, '')
    // Replace spaces and multiple hyphens with a single hyphen
    .replace(/[\s-]+/g, '-')
    // Remove leading/trailing hyphens
    .replace(/^-+|-+$/g, '');
}).filter(Boolean);
return { output: lines.join('\n'), outputLanguage: 'text' };
